import{c as t,Q as a,j as s,m as n}from"./chunks/framework.iD28w_5a.js";const k=JSON.parse('{"title":"Phase 0-A 重构日志","description":"","frontmatter":{"title":"Phase 0-A 重构日志"},"headers":[],"relativePath":"notes/2026-05-22_phase0a_refactor.md","filePath":"notes/2026-05-22_phase0a_refactor.md","lastUpdated":1779686691000}'),p={name:"notes/2026-05-22_phase0a_refactor.md"};function i(l,e,r,d,c,o){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="phase-0-a-重构开发日志-2026-05-22" tabindex="-1">Phase 0-A 重构开发日志 (2026-05-22) <a class="header-anchor" href="#phase-0-a-重构开发日志-2026-05-22" aria-label="Permalink to &quot;Phase 0-A 重构开发日志 (2026-05-22)&quot;">​</a></h1><blockquote><p>分支：<code>optimize/optimize_tutorials_for_release</code> 提交：<code>145b488 optimize: update the code quality</code></p></blockquote><h2 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h2><p>Phase 0 是所有 Feature 域开发的前置阶段，分为 0-A（CMake 架构升级 + 大文件拆分）、0-B（代码优化）、0-C（注释覆盖）三个串行子阶段。本次完成 0-A。</p><p>核心问题：两个巨型文件（ext2.cpp 1810 行、process.cpp 937 行）严重超标 500 行硬上限，kernel/CMakeLists.txt 把 68 个源文件堆在一个 OBJECT 库里，test/CMakeLists.txt 有 866 行重复样板代码。这些在开发后期会造成维护困难、编译时间增长、CI 无法自动检查行数合规。</p><h2 id="重构手段" tabindex="-1">重构手段 <a class="header-anchor" href="#重构手段" aria-label="Permalink to &quot;重构手段&quot;">​</a></h2><h3 id="_1-ext2-cpp-拆分-1810-行-→-5-个文件" tabindex="-1">1. ext2.cpp 拆分（1810 行 → 5 个文件） <a class="header-anchor" href="#_1-ext2-cpp-拆分-1810-行-→-5-个文件" aria-label="Permalink to &quot;1. ext2.cpp 拆分（1810 行 → 5 个文件）&quot;">​</a></h3><p>按照逻辑功能点拆分，每个文件保持 ≤500 行：</p><table tabindex="0"><thead><tr><th>文件</th><th>行数</th><th>职责</th></tr></thead><tbody><tr><td>ext2_common.cpp</td><td>~320</td><td>Ext2FileOps / Ext2DirOps 的 VFS InodeOps 桥接实现</td></tr><tr><td>ext2_init.cpp</td><td>~310</td><td>构造函数、DMA buffer、mount()、块 I/O、超级块/BGDT 写回、路径解析</td></tr><tr><td>ext2_inode.cpp</td><td>~395</td><td>inode 读写、分配/释放、缓存管理、get_or_alloc_block()</td></tr><tr><td>ext2_block.cpp</td><td>~155</td><td>数据块 bitmap 扫描、分配/释放、元数据计数更新</td></tr><tr><td>ext2_directory.cpp</td><td>~470</td><td>目录项插入/删除、create()、mkdir()、unlink()</td></tr></tbody></table><p>头文件也做了相应拆分：</p><ul><li><code>ext2_common.hpp</code> 提取了 Ext2FileOps、Ext2DirOps 类定义和 EXT2_MAX_GROUPS 常量，避免 ext2.hpp 膨胀</li><li><code>ext2.hpp</code> 保留为统一入口，include ext2_common.hpp + ext2_types.hpp</li><li><code>ext2_types.hpp</code> 不变（磁盘结构体和常量）</li><li>外部调用方（proc/init.cpp、测试文件等）无需任何改动</li></ul><p>拆分原则：所有方法仍属于 Ext2 类，只是实现分散到多个 .cpp 文件。这是 C++ 的标准做法——类定义在头文件，实现可以分布在多个翻译单元。函数之间的调用关系决定了归属：例如 lookup_in_dir/lookup 放在 ext2_init.cpp 因为它们是 mount 后的路径导航基础设施，而 create/mkdir/unlink 放在 ext2_directory.cpp 因为它们是目录变更操作。</p><h3 id="_2-process-cpp-拆分-937-行-→-4-个文件" tabindex="-1">2. process.cpp 拆分（937 行 → 4 个文件） <a class="header-anchor" href="#_2-process-cpp-拆分-937-行-→-4-个文件" aria-label="Permalink to &quot;2. process.cpp 拆分（937 行 → 4 个文件）&quot;">​</a></h3><p>原计划 3 个文件，但 fork + execve 的内部辅助函数合计 ~760 行，超过 500 行限制，因此拆为 4 个：</p><table tabindex="0"><thead><tr><th>文件</th><th>行数</th><th>职责</th></tr></thead><tbody><tr><td>process_new.cpp</td><td>~260</td><td>共享内部状态（next_tid、栈地址分配器）、CoW page fault 处理、waitpid()</td></tr><tr><td>task_builder.cpp</td><td>~160</td><td>TaskBuilder setter 和 build() 实现</td></tr><tr><td>fork.cpp</td><td>~280</td><td>fork() 实现 + CoW 页表递归拷贝</td></tr><tr><td>execve.cpp</td><td>~290</td><td>execve() 实现 + ELF 校验 / 用户空间清空</td></tr></tbody></table><p>共享状态处理：原代码中 <code>next_tid</code> 和 <code>alloc_stack_vaddr()</code> 在匿名命名空间里，拆分后需要跨文件共享。解决方案是创建 <code>process_internal.hpp</code>，声明 extern 变量和函数，实际定义在 process_new.cpp 中。</p><h3 id="_3-cmake-子模块化" tabindex="-1">3. CMake 子模块化 <a class="header-anchor" href="#_3-cmake-子模块化" aria-label="Permalink to &quot;3. CMake 子模块化&quot;">​</a></h3><p>kernel/CMakeLists.txt 从内联 68 个源文件改为 <code>add_subdirectory</code> 模式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kernel/CMakeLists.txt          ← 创建空 OBJECT 库，add_subdirectory 聚合</span></span>
<span class="line"><span>kernel/arch/CMakeLists.txt     ← arch 源文件（boot.S, gdt.cpp, ...）</span></span>
<span class="line"><span>kernel/drivers/CMakeLists.txt  ← 驱动源文件（含 GUI 条件编译）</span></span>
<span class="line"><span>kernel/fs/CMakeLists.txt       ← 文件系统源文件</span></span>
<span class="line"><span>kernel/mm/CMakeLists.txt       ← 内存管理源文件</span></span>
<span class="line"><span>kernel/proc/CMakeLists.txt     ← 进程管理源文件</span></span>
<span class="line"><span>kernel/syscall/CMakeLists.txt  ← 系统调用源文件</span></span>
<span class="line"><span>kernel/ipc/CMakeLists.txt      ← IPC 源文件</span></span>
<span class="line"><span>kernel/lib/CMakeLists.txt      ← 基础库源文件</span></span>
<span class="line"><span>kernel/gui/CMakeLists.txt      ← GUI 源文件（已有，保留）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>采用 <code>target_sources(big_kernel_common PRIVATE ...)</code> 模式而非独立 OBJECT 库，理由：</p><ul><li>与已有 gui/CMakeLists.txt 保持一致</li><li>避免为每个子库重复设置编译选项</li><li>编译选项统一在父 CMakeLists.txt 设置一次</li></ul><h3 id="_4-test-cmakelists-txt-精简-866-行-→-200-行" tabindex="-1">4. test/CMakeLists.txt 精简（866 行 → ~200 行） <a class="header-anchor" href="#_4-test-cmakelists-txt-精简-866-行-→-200-行" aria-label="Permalink to &quot;4. test/CMakeLists.txt 精简（866 行 → ~200 行）&quot;">​</a></h3><p>引入两个辅助函数消除重复样板：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">function(add_cinux_test name)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 简单测试：unit/test_&lt;name&gt;.cpp</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">function(add_cinux_integration_test name)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 集成测试：自定义源文件列表</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">endfunction()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>同时把 <code>test_host</code>、<code>test_all</code>、<code>test_verbose</code> 的 DEPENDS 列表提取为 <code>ALL_HOST_TESTS</code> 变量，一处维护。</p><h3 id="_5-ci-行数检查" tabindex="-1">5. CI 行数检查 <a class="header-anchor" href="#_5-ci-行数检查" aria-label="Permalink to &quot;5. CI 行数检查&quot;">​</a></h3><p>新增 <code>scripts/check_line_limits.py</code>：扫描 kernel/（排除 mini/ 和 test/），.cpp/.S 文件限制 500 行，.h/.hpp 文件限制 500 行（建议 300 行）。CI 新增 <code>line-limits</code> job 在格式化后、构建前运行。</p><h2 id="验证结果" tabindex="-1">验证结果 <a class="header-anchor" href="#验证结果" aria-label="Permalink to &quot;验证结果&quot;">​</a></h2><ul><li><code>cmake --build build/</code> 完整构建通过（内核 + host 测试）</li><li>全部 41 个 host 单元测试通过</li><li>全部 662 个 kernel (QEMU) 测试通过</li><li><code>python3 scripts/check_line_limits.py --hpp 500</code> 全部通过</li><li>所有 .cpp 文件 ≤ 500 行</li></ul>`,29)])])}const u=t(p,[["render",i]]);export{k as __pageData,u as default};
